1	export interface QuoteInput {
2	  customer?: { yearsWithMHPCO: number };
3	  items: { type: string; cursed?: boolean; enchantment?: number }[];
4	}
5	
6	const PROCESSING_FEE = 5;
7	
8	const BLOCK_SIZE = 3;
9	const BLOCK_PRICE = 60;
10	
11	const CURSE_SURCHARGE_RATE = 0.5;
12	
13	const HIGH_ENCHANTMENT_THRESHOLD = 5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	
16	const LOYALTY_MINIMUM_YEARS = 2;
17	const LOYALTY_DISCOUNT_RATE = 0.2;
18	
19	const BASE_PREMIUMS: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: 25,
25	  moonstone: 25,
26	};
27	
28	export function quote(input: QuoteInput): number {
29	  const countsByType: Record<string, number> = {};
30	  for (const item of input.items) {
31	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
32	  }
33	
34	  let basePremiumTotal = 0;
35	  for (const type of Object.keys(countsByType)) {
36	    const count = countsByType[type];
37	    if (count === BLOCK_SIZE) {
38	      basePremiumTotal += BLOCK_PRICE;
39	    } else {
40	      basePremiumTotal += count * BASE_PREMIUMS[type];
41	    }
42	  }
43	
44	  let surchargeTotal = 0;
45	  for (const item of input.items) {
46	    if (item.cursed) {
47	      surchargeTotal += BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE;
48	    }
49	    if (
50	      item.enchantment !== undefined &&
51	      item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
52	    ) {
53	      surchargeTotal +=
54	        BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
55	    }
56	  }
57	
58	  let loyaltyDiscount = 0;
59	  if (
60	    input.customer !== undefined &&
61	    input.customer.yearsWithMHPCO >= LOYALTY_MINIMUM_YEARS
62	  ) {
63	    loyaltyDiscount = basePremiumTotal * LOYALTY_DISCOUNT_RATE;
64	  }
65	
66	  return basePremiumTotal - loyaltyDiscount + surchargeTotal + PROCESSING_FEE;
67	}
68	
69	export function claim(): number {
70	  return undefined as unknown as number;
71	}
